mapper.update:
update dm_exec_sql_audit
set status = #{status},affect_line = #{affectLine},status = #{status},message = #{message},end_time = #{time}
where session_id = #{sessionId} and status = 'RUNNING'

mapper.select:
select

from
    dm_exec_sql_audit
WHERE 1=1
AND primary_uid = #{puid}

     AND id < #{startId} 


    AND uid = #{uid}


     AND gmt_create >= #{dateStart} 


     AND gmt_create <= #{dateEnd} 


     AND sql_kind = #{sqlKind} 


     AND status = #{status} 


     AND requester = #{requester} 


     AND resource like CONCAT('%',#{resourcePath},'%') 


     AND ds_id = #{dsId} 

ORDER BY operate_time DESC,id LIMIT #{pageSize}
